    Creating a Memcached object


<?php
/* Criar uma instância regular */
$m = new Memcached();
echo get_class($m);

/* Criar uma instância persistente */
$m2 = new Memcached('story_pool');
$m3 = new Memcached('story_pool');

/* agora $m2 e $m3 compartilham a mesma conexão */
?>
